{"file_path": "/home/wendirad/Work/eaglepointai/w1t22/repo/server/src/middleware/field-mask.ts", "content": "import { Request, Response, NextFunction } from 'express';
import { Role } from '../types/enums';

interface MaskRule {
  field: string;
  visibleChars: number;
  allowedRoles: Role[];
}

const MASK_RULES: MaskRule[] = [
  {
    field: 'driversLicense',
    visibleChars: 4,
    allowedRoles: [Role.ADMIN, Role.FINANCE_REVIEWER],
  },
  {
    field: 'ssn',
    visibleChars: 4,
    allowedRoles: [Role.ADMIN, Role.FINANCE_REVIEWER],
  },
  {
    field: 'phone',
    visibleChars: 4,
    allowedRoles: [Role.ADMIN, Role.DEALERSHIP_STAFF, Role.FINANCE_REVIEWER],
  },
];

function maskValue(value: string, visibleChars: number): string {
  if (value.length <= visibleChars) return value;
  const visible = value.slice(-visibleChars);
  const masked = '*'.repeat(value.length - visibleChars);
  return masked + visible;
}

function applyMask(obj: any, role: Role): any {
  if (!obj || typeof obj !== 'object') return obj;

  if (Array.isArray(obj)) {
    return obj.map((item) => applyMask(item, role));
  }

  const result = { ...obj };
  if (result._doc) {
    return applyMask(result._doc, role);
  }

  for (const rule of MASK_RULES) {
    if (result[rule.field] && !rule.allowedRoles.includes(role)) {
      result[rule.field] = maskValue(String(result[rule.field]), rule.visibleChars);
    }
  }

  for (const key of Object.keys(result)) {
    if (typeof result[key] === 'object' && result[key] !== null) {
      result[key] = applyMask(result[key], role);
    }
  }

  return result;
}

export function fieldMask(req: Request, res: Response, next: NextFunction): void {
  const originalJson = res.json.bind(res);

  res.json = function (body: any) {
    if (req.user) {
      body = applyMask(body, req.user.role as Role);
    }
    return originalJson(body);
  };

  next();
}
"}

