  );
  if (!vehicle) {
    throw new BadRequestError('Vehicle is not available for reservation');
  }
  return vehicle;
}

export async function releaseVehicle(vehicleId: string) {
  await Vehicle.findByIdAndUpdate(vehicleId, { status: VehicleStatus.AVAILABLE });
}

