                </svg>
                {item.label}
                {item.path === '/cart' && itemCount > 0 && (
                  <span className="ml-auto bg-primary-600 text-white text-xs rounded-full px-2 py-0.5">
                    {itemCount}
                  </span>
                )}
              </Link>
            );
          })}
        </nav>

        <div className="p-3 border-t border-gray-200">
          <div className="flex items-center gap-3 px-3 py-2">
