          >
            {uploadForm.file ? (
              <p className="font-medium">{uploadForm.file.name}</p>
            ) : (
              <div>
                <p className="text-gray-500">Drag & drop a file here, or</p>
                <label className="btn-secondary mt-2 inline-block cursor-pointer">
                  Browse Files
                  <input
