14	function request(method, path, body, token) {
15	  return new Promise((resolve, reject) => {
16	    const url = new URL(path, BASE_URL);
17	    const options = {
18	      hostname: url.hostname,
19	      port: url.port,
20	      path: url.pathname + url.search,
21	      method,
22	      headers: {
23	        'Content-Type': 'application/json',
24	        'X-Timestamp': new Date().toISOString(),
25	      },
26	    };
27	
28	    if (token) options.headers['Authorization'] = `Bearer ${token}`;
29	
30	    const req = http.request(options, (res) => {
31	      let data = '';
32	      res.on('data', (chunk) => { data += chunk; });
33	      res.on('end', () => {
34	        let parsed;
35	        try { parsed = JSON.parse(data); } catch { parsed = data; }
36	        resolve({ status: res.statusCode, data: parsed });
37	      });
38	    });
39	
40	    req.on('error', reject);
41	    if (body) req.write(JSON.stringify(body));
42	    req.end();
43	  });
44	}
