const http = require('http');
function req(method, path, body, token) {
  return new Promise((resolve, reject) => {
    const opt = {hostname:'localhost',port:5000,path,method,headers:{'Content-Type':'application/json','X-Timestamp':new Date().toISOString()}};
    if(token) opt.headers['Authorization'] = 'Bearer '+token;
    const r = http.request(opt, res => {
      let d=''; res.on('data',c=>d+=c); res.on('end',()=>{try{resolve({s:res.statusCode,d:JSON.parse(d)})}catch{resolve({s:res.statusCode,d})}});
    });
    r.on('error',reject);
    if(body)r.write(JSON.stringify(body));r.end();
  });
}
async function run(){
  // Login all roles
  const admin = await req('POST','/api/v1/auth/login',{email:process.env.ADMIN_EMAIL,password:process.env.ADMIN_PASSWORD});
  const staff = await req('POST','/api/v1/auth/login',{email:process.env.STAFF_EMAIL,password:process.env.STAFF_PASSWORD});
  const finance = await req('POST','/api/v1/auth/login',{email:process.env.FINANCE_EMAIL,password:process.env.FINANCE_PASSWORD});
  const buyer = await req('POST','/api/v1/auth/login',{email:process.env.BUYER_EMAIL,password:process.env.BUYER_PASSWORD});

  const at = admin.d.accessToken, st = staff.d.accessToken, ft = finance.d.accessToken, bt = buyer.d.accessToken;
  console.log('=== LOGIN STATUS ===');
  console.log('admin:', admin.s, 'dealershipId:', admin.d.user?.dealershipId);
  console.log('staff:', staff.s, 'dealershipId:', staff.d.user?.dealershipId);
  console.log('finance:', finance.s, 'dealershipId:', finance.d.user?.dealershipId);
  console.log('buyer:', buyer.s, 'dealershipId:', buyer.d.user?.dealershipId);

  // Cart tests per role
  console.log('');
  console.log('=== CART PER ROLE ===');
  for (const [name, token, did] of [['admin',at,admin.d.user?.dealershipId],['staff',st,staff.d.user?.dealershipId],['finance',ft,finance.d.user?.dealershipId],['buyer',bt,buyer.d.user?.dealershipId]]) {
    const qs = did ? '?dealershipId='+did : '';
    const r = await req('GET','/api/v1/cart'+qs,null,token);
    console.log(name+' GET /cart:', r.s, r.s!==200 ? JSON.stringify(r.d) : 'items='+r.d.items?.length);
  }

  // Dealerships per role
  console.log('');
  console.log('=== DEALERSHIPS PER ROLE ===');
  for (const [name, token] of [['admin',at],['staff',st],['finance',ft],['buyer',bt]]) {
    const r = await req('GET','/api/v1/admin/dealerships',null,token);
    console.log(name+' GET /admin/dealerships:', r.s, r.s===200 ? 'count='+r.d.length : JSON.stringify(r.d));
  }

  // Vehicles per role
  console.log('');
  console.log('=== VEHICLES PER ROLE ===');
  for (const [name, token] of [['admin',at],['staff',st],['finance',ft],['buyer',bt],['anon',null]]) {
    const r = await req('GET','/api/v1/vehicles',null,token);
    console.log(name+' GET /vehicles:', r.s, r.s===200 ? 'count='+r.d.data?.length : JSON.stringify(r.d));
  }

  // Orders per role
  console.log('');
  console.log('=== ORDERS PER ROLE ===');
  for (const [name, token] of [['admin',at],['staff',st],['finance',ft],['buyer',bt]]) {
    const r = await req('GET','/api/v1/orders',null,token);
    console.log(name+' GET /orders:', r.s, r.s===200 ? 'count='+r.d.data?.length : JSON.stringify(r.d));
  }

  // Documents per role
  console.log('');
  console.log('=== DOCUMENTS PER ROLE ===');
  for (const [name, token] of [['admin',at],['staff',st],['finance',ft],['buyer',bt]]) {
    const r = await req('GET','/api/v1/documents',null,token);
    console.log(name+' GET /documents:', r.s, r.s===200 ? 'count='+r.d.data?.length : JSON.stringify(r.d));
  }

  // Finance per role
  console.log('');
  console.log('=== FINANCE PER ROLE ===');
  for (const [name, token] of [['admin',at],['staff',st],['finance',ft],['buyer',bt]]) {
    const r = await req('GET','/api/v1/finance/wallet/balance',null,token);
    console.log(name+' GET /finance/wallet/balance:', r.s, r.s===200 ? JSON.stringify(r.d) : JSON.stringify(r.d));
  }

  // Admin-only endpoints with non-admin
  console.log('');
  console.log('=== ADMIN-ONLY RBAC ===');
  for (const [name, token] of [['admin',at],['staff',st],['finance',ft],['buyer',bt]]) {
    const r = await req('GET','/api/v1/admin/users',null,token);
    console.log(name+' GET /admin/users:', r.s);
  }

  // Audit per role
  console.log('');
  console.log('=== AUDIT PER ROLE ===');
  for (const [name, token] of [['admin',at],['staff',st],['finance',ft],['buyer',bt]]) {
    const r = await req('GET','/api/v1/audit',null,token);
    console.log(name+' GET /audit:', r.s);
  }

  // Register test (no dealership list for anon)
  console.log('');
  console.log('=== REGISTER FLOW ===');
  const dealerships_anon = await req('GET','/api/v1/admin/dealerships');
  console.log('anon GET /admin/dealerships:', dealerships_anon.s, dealerships_anon.s===200 ? 'count='+dealerships_anon.d.length : JSON.stringify(dealerships_anon.d));
}
run().catch(e => console.error(e));
