4	import { formatCurrency } from '../../../shared/utils/formatCurrency';
5	import { useAuth } from '../../auth/context/AuthContext';
6	import Spinner from '../../../shared/components/ui/Spinner';
7	import ErrorMessage from '../../../shared/components/ui/ErrorMessage';
8	import { v4 as uuidv4 } from 'react-router-dom';
9	import { useState } from 'react';
10	
11	export default function CartPage() {
12	  const { user } = useAuth();
13	  const navigate = useNavigate();
14	  const queryClient = useQueryClient();
15	  const [checkoutError, setCheckoutError] = useState('');
16	
17	  const { data: cart, isLoading, error, refetch } = useQuery({
18	    queryKey: ['cart'],
19	    queryFn: () => httpClient.get('/cart').then((r) => r.data),
20	  });
21	
22	  const removeItem = useMutation({
23	    mutationFn: (vehicleId: string) => httpClient.delete(`/cart/items/${vehicleId}`),
24	    onSuccess: () => { queryClient.invalidateQueries({ queryKey: ['cart'] }); },
25	  });
26	
27	  const checkout = useMutation({
28	    mutationFn: () =>
29	      httpClient.post('/orders', {
30	        idempotencyKey: `checkout-${user?._id}-${Date.now()}`,
31	      }),
32	    onSuccess: (data) => {
33	      queryClient.invalidateQueries({ queryKey: ['cart'] });
34	      const orderId = Array.isArray(data.data) ? data.data[0]._id : data.data._id;
35	      navigate(`/orders/${orderId}`);
36	    },
37	    onError: (err: any) => {
38	      setCheckoutError(err.response?.data?.msg || 'Checkout failed');
39	    },
40	  });
41	
42	  if (isLoading) return <Spinner className="py-12" />;
43	  if (error) return <ErrorMessage message="Failed to load cart" onRetry={() => refetch()} />;
44	
45	  const items = cart?.items || [];
46	  const subtotal = items.reduce((sum: number, item: any) => {
47	    const vehiclePrice = item.vehicleId?.price || 0;
48	    const addOnTotal = item.addOnServices?.reduce((s: number, a: any) => s + a.price, 0) || 0;
49	    return sum + vehiclePrice + addOnTotal;
50	  }, 0);
51	
52	  return (
53	    <div>
54	      <h1 className="text-2xl font-bold text-gray-900 mb-6">Shopping Cart</h1>
55	
56	      {items.length === 0 ? (
57	        <div className="card text-center py-12">
58	          <svg className="h-12 w-12 text-gray-300 mx-auto mb-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
59	            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M3 3h2l.4 2M7 13h10l4-8H5.4M7 13L5.4 5M7 13l-2.293 2.293c-.63.63-.184 1.707.707 1.707H17m0 0a2 2 0 100 4 2 2 0 000-4zm-8 2a2 2 0 100 4 2 2 0 000-4z" />
60	          </svg>
61	          <h3 className="text-lg font-medium text-gray-900 mb-1">Cart is empty</h3>
62	          <p className="text-gray-500 mb-4">Browse vehicles and add them to your cart.</p>
63	          <button onClick={() => navigate('/vehicles')} className="btn-primary">Browse Vehicles</button>
64	        </div>
65	      ) : (
66	        <div className="grid grid-cols-3 gap-6">
67	          <div className="col-span-2 space-y-4">
68	            {items.map((item: any) => {
69	              const vehicle = item.vehicleId;
70	              if (!vehicle) return null;
71	              return (
72	                <div key={vehicle._id} className="card flex items-center gap-4">
73	                  <div className="w-16 h-16 bg-gray-100 rounded-lg flex items-center justify-center">
74	                    <svg className="h-8 w-8 text-gray-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
75	                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M9 17a2 2 0 11-4 0 2 2 0 014 0zM19 17a2 2 0 11-4 0 2 2 0 014 0z" />
76	                    </svg>
77	                  </div>
78	                  <div className="flex-1">
79	                    <h3 className="font-semibold">{vehicle.year} {vehicle.make} {vehicle.model}</h3>
80	                    <p className="text-sm text-gray-500">{vehicle.trim} | {vehicle.mileage?.toLocaleString()} mi</p>
81	                    {item.addOnServices?.length > 0 && (
82	                      <div className="mt-1 flex gap-2">
83	                        {item.addOnServices.map((a: any) => (
84	                          <span key={a.serviceCode} className="badge bg-blue-50 text-blue-700">{a.name}</span>
85	                        ))}
86	                      </div>
87	                    )}
88	                  </div>
89	                  <div className="text-right">
90	                    <p className="font-bold text-lg">{formatCurrency(vehicle.price)}</p>
91	                    {item.addOnServices?.length > 0 && (
92	                      <p className="text-sm text-gray-500">
93	                        + {formatCurrency(item.addOnServices.reduce((s: number, a: any) => s + a.price, 0))} add-ons
94	                      </p>
95	                    )}
96	                  </div>
97	                  <button
98	                    onClick={() => removeItem.mutate(vehicle._id)}
99	                    disabled={removeItem.isPending}
100	                    className="text-red-500 hover:text-red-700 p-2"
101	                  >
102	                    <svg className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
103	                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
104	                    </svg>
105	                  </button>
106	                </div>
107	              );
108	            })}
109	          </div>
110	
111	          <div className="card h-fit">
112	            <h3 className="font-semibold text-gray-900 mb-4">Order Summary</h3>
113	            <div className="space-y-2 text-sm">
114	              <div className="flex justify-between">
115	                <span className="text-gray-600">Items ({items.length})</span>
116	                <span className="font-medium">{formatCurrency(subtotal)}</span>
117	              </div>
118	              <div className="flex justify-between">
119	                <span className="text-gray-600">Tax</span>
120	                <span className="text-gray-500">Calculated at checkout</span>
121	              </div>
122	              <div className="border-t pt-2 flex justify-between text-base">
123	                <span className="font-semibold">Subtotal</span>
124	                <span className="font-bold text-primary-600">{formatCurrency(subtotal)}</span>
125	              </div>
126	            </div>
127	
128	            {checkoutError && (
129	              <div className="mt-3 text-sm text-red-600 bg-red-50 p-2 rounded">{checkoutError}</div>
130	            )}
131	
132	            <button
133	              onClick={() => checkout.mutate()}
134	              disabled={checkout.isPending}
135	              className="btn-primary w-full mt-4 flex items-center justify-center gap-2"
136	            >
137	              {checkout.isPending && <Spinner size="sm" />}
138	              {checkout.isPending ? 'Processing...' : 'Proceed to Checkout'}
139	            </button>
140	            <p className="text-xs text-gray-400 mt-2 text-center">
141	              Orders may split based on supplier/warehouse
142	            </p>
143	          </div>
144	        </div>
145	      )}
146	    </div>
147	  );
148	}
149

