const http = require('http');
function req(method, path, body, token) {
  return new Promise((resolve, reject) => {
    const opt = {hostname:'localhost',port:5000,path,method,headers:{'Content-Type':'application/json','X-Timestamp':new Date().toISOString()}};
    if(token) opt.headers['Authorization'] = 'Bearer '+token;
    const r = http.request(opt, res => {
      let d=''; res.on('data',c=>d+=c); res.on('end',()=>{try{resolve({s:res.statusCode,d:JSON.parse(d)})}catch{resolve({s:res.statusCode,d})}});
    });
    r.on('error',reject);
    if(body)r.write(JSON.stringify(body));r.end();
  });
}
async function run(){
  const admin = await req('POST','/api/v1/auth/login',{email:process.env.ADMIN_EMAIL,password:process.env.ADMIN_PASSWORD});
  const staff = await req('POST','/api/v1/auth/login',{email:process.env.STAFF_EMAIL,password:process.env.STAFF_PASSWORD});
  const finance = await req('POST','/api/v1/auth/login',{email:process.env.FINANCE_EMAIL,password:process.env.FINANCE_PASSWORD});
  const buyer = await req('POST','/api/v1/auth/login',{email:process.env.BUYER_EMAIL,password:process.env.BUYER_PASSWORD});
  const at=admin.d.accessToken, st=staff.d.accessToken, ft=finance.d.accessToken, bt=buyer.d.accessToken;
  const did = staff.d.user.dealershipId;

  console.log('=== CART PER ROLE ===');
  for (const [name,token,d] of [['admin',at,did],['staff',st,null],['finance',ft,null],['buyer',bt,null]]) {
    const qs = d ? '?dealershipId='+d : '';
    const r = await req('GET','/api/v1/cart'+qs,null,token);
    console.log(name+': '+r.s+(r.s===200 ? ' items='+r.d.items?.length : ' '+JSON.stringify(r.d)));
  }

  console.log('');
  console.log('=== PUBLIC DEALERSHIPS (for register) ===');
  const dealAnon = await req('GET','/api/v1/dealerships');
  console.log('anon: '+dealAnon.s+' count='+(dealAnon.d?.length || 0));

  console.log('');
  console.log('=== WALLET PER ROLE ===');
  for (const [name,token] of [['admin',at],['staff',st],['finance',ft],['buyer',bt]]) {
    const r = await req('GET','/api/v1/finance/wallet/balance',null,token);
    console.log(name+': '+r.s+' '+JSON.stringify(r.d));
  }

  console.log('');
  console.log('=== ORDERS PER ROLE ===');
  for (const [name,token] of [['admin',at],['staff',st],['finance',ft],['buyer',bt]]) {
    const r = await req('GET','/api/v1/orders',null,token);
    console.log(name+': '+r.s+' count='+r.d.data?.length);
  }

  console.log('');
  console.log('=== ADMIN-ONLY RBAC ===');
  for (const [name,token] of [['admin',at],['staff',st],['finance',ft],['buyer',bt]]) {
    const users = await req('GET','/api/v1/admin/users',null,token);
    const experiments = await req('GET','/api/v1/admin/experiments',null,token);
    const audit = await req('GET','/api/v1/audit',null,token);
    console.log(name+': users='+users.s+' experiments='+experiments.s+' audit='+audit.s);
  }

  console.log('');
  console.log('=== VEHICLES SCOPE ===');
  for (const [name,token] of [['admin',at],['staff',st],['buyer',bt],['anon',null]]) {
    const r = await req('GET','/api/v1/vehicles',null,token);
    console.log(name+': '+r.s+' count='+r.d.data?.length);
  }
}
run().catch(e => console.error(e));
